## VIDA Runtime Agent Inventory — derive concrete installed agents from overlay/runtime.
##
## Product law stays in `vida/config/agents/*`.
## Concrete executable inventory is built from `vida.config.yaml` plus runtime detection.

import std/[json, os, strutils]
import ./[config, kernel_config, utils]

proc runtimeAgentType(subagentCfg: JsonNode): string =
  let backend = dottedGetStr(subagentCfg, "subagent_backend_class", "external_cli")
  case backend
  of "internal", "system":
    "system_agent"
  of "human", "human_agent":
    "human_agent"
  of "service", "service_agent":
    "service_agent"
  else:
    "llm_agent"

proc detectOverlaySubagents(cfg: JsonNode): JsonNode =
  let subagents = getSubagents(cfg)
  result = newJObject()
  if subagents.kind != JObject:
    return

  for name, subCfg in subagents:
    if subCfg.kind != JObject:
      continue
    let enabled = dottedGetBool(subCfg, "enabled", false)
    var detectCmd = dottedGetStr(subCfg, "detect_command")
    var available = false
    if name == "internal_subagents":
      available = enabled
    else:
      if detectCmd.len == 0:
        detectCmd = name.replace("_cli", "")
      available = enabled and findExe(detectCmd).len > 0
    result[name] = %*{
      "enabled": enabled,
      "available": available,
      "detect_command": detectCmd,
    }

proc hasAny(values, required: seq[string]): bool =
  if required.len == 0:
    return true
  for value in values:
    if value in required:
      return true
  false

proc hasAll(values, required: seq[string]): bool =
  if required.len == 0:
    return true
  for item in required:
    if item notin values:
      return false
  true

proc matchesSelector(selector, traits: JsonNode): bool =
  if selector.kind != JObject:
    return false

  let requireAvailable = dottedGetBool(selector, "require_available", true)
  if requireAvailable and not dottedGetBool(traits, "available", false):
    return false

  let capabilityBand = splitCsv(traits{"capability_band"})
  let writeScopes = @[policyValue(traits{"write_scope"}, "none")]
  let agentTypes = @[policyValue(traits{"agent_type"}, "llm_agent")]
  let tiers = @[policyValue(traits{"orchestration_tier"}, "standard")]
  let specialties = splitCsv(traits{"specialties"})
  let billingTiers = @[policyValue(traits{"billing_tier"}, "unknown")]
  let qualityTiers = @[policyValue(traits{"quality_tier"}, "unknown")]

  if not hasAny(capabilityBand, splitCsv(selector{"capability_band_any"})):
    return false
  if not hasAll(capabilityBand, splitCsv(selector{"capability_band_all"})):
    return false
  if not hasAny(writeScopes, splitCsv(selector{"write_scopes_any"})):
    return false
  if not hasAny(agentTypes, splitCsv(selector{"agent_types_any"})):
    return false
  if not hasAny(tiers, splitCsv(selector{"orchestration_tiers_any"})):
    return false
  if not hasAny(specialties, splitCsv(selector{"specialties_any"})):
    return false
  if not hasAny(billingTiers, splitCsv(selector{"billing_tiers_any"})):
    return false
  if not hasAny(qualityTiers, splitCsv(selector{"quality_tiers_any"})):
    return false

  true

proc resolveWorkflowRoles(traits, groupsDoc: JsonNode): seq[string] =
  let groups = dottedGet(groupsDoc, "groups")
  if groups.kind != JObject:
    return @[]

  for _, payload in groups:
    if payload.kind != JObject:
      continue
    if dottedGetBool(payload, "manual_only", false):
      continue
    let workflowRole = dottedGetStr(payload, "workflow_role")
    if workflowRole.len == 0:
      continue
    if matchesSelector(dottedGet(payload, "selector"), traits) and workflowRole notin result:
      result.add(workflowRole)

proc deriveCapabilities(workflowRoles: seq[string], subCfg: JsonNode): seq[string] =
  for capability in splitCsv(subCfg{"specialties"}):
    if capability notin result:
      result.add(capability)
  for capability in splitCsv(subCfg{"capability_band"}):
    if capability notin result:
      result.add(capability)

  for role in workflowRoles:
    let roleCapability =
      case role
      of "analyst": "analysis"
      of "writer": "implementation"
      of "coach": "review"
      of "verifier": "verification"
      of "approver": "approval"
      of "synthesizer": "synthesis"
      of "orchestrator": "escalation"
      else: ""
    if roleCapability.len > 0 and roleCapability notin result:
      result.add(roleCapability)

proc overlayTraits(name: string, subCfg, detected: JsonNode): JsonNode =
  let enabled = dottedGetBool(subCfg, "enabled", false)
  let available = dottedGetBool(detected, "available", false)
  %*{
    "id": name,
    "enabled": enabled,
    "available": available,
    "agent_type": runtimeAgentType(subCfg),
    "overlay_role": dottedGetStr(subCfg, "role", "secondary"),
    "orchestration_tier": dottedGetStr(subCfg, "orchestration_tier", "standard"),
    "cost_priority": dottedGetStr(subCfg, "cost_priority", "normal"),
    "budget_cost_units": policyInt(subCfg{"budget_cost_units"}, 0),
    "capability_band": splitCsv(subCfg{"capability_band"}),
    "write_scope": dottedGetStr(subCfg, "write_scope", "none"),
    "billing_tier": dottedGetStr(subCfg, "billing_tier", "unknown"),
    "speed_tier": dottedGetStr(subCfg, "speed_tier", "unknown"),
    "quality_tier": dottedGetStr(subCfg, "quality_tier", "unknown"),
    "specialties": splitCsv(subCfg{"specialties"}),
    "max_concurrency": policyInt(subCfg{"max_concurrency"}, 1),
    "priority": 0,
    "max_runtime_seconds": policyInt(subCfg{"max_runtime_seconds"}, 0),
    "min_output_bytes": policyInt(subCfg{"min_output_bytes"}, 0),
  }

proc computePriority(subCfg, assignmentPolicy: JsonNode): int =
  let costPriority = dottedGetStr(subCfg, "cost_priority", "normal")
  let billingTier = dottedGetStr(subCfg, "billing_tier", "unknown")
  let qualityTier = dottedGetStr(subCfg, "quality_tier", "unknown")
  let speedTier = dottedGetStr(subCfg, "speed_tier", "unknown")
  let enabled = dottedGetBool(subCfg, "enabled", false)
  if not enabled:
    return 0

  result = 50
  case costPriority
  of "premium": result += 35
  of "fallback": result += 10
  of "highest": result += 20
  else: discard

  case billingTier
  of "internal": result += 20
  of "low": result += 10
  of "free": result += 5
  else: discard

  case qualityTier
  of "high": result += 15
  of "medium": result += 5
  else: discard

  case speedTier
  of "fast": result += 10
  of "medium": result += 5
  else: discard

  let maxParallel = policyInt(dottedGet(assignmentPolicy, "runtime.max_parallel_agents"), 1)
  if maxParallel > 1:
    result += min(maxParallel, 5)

proc buildAgentEntry(name: string, subCfg, detected, groupsDoc, assignmentPolicy: JsonNode): JsonNode =
  let traits = overlayTraits(name, subCfg, detected)
  let workflowRoles = resolveWorkflowRoles(traits, groupsDoc)
  let capabilities = deriveCapabilities(workflowRoles, subCfg)
  result = normalizeJson(traits)
  result["status"] =
    (if not dottedGetBool(subCfg, "enabled", false): %"disabled"
     elif dottedGetBool(detected, "available", false): %"active"
     else: %"unavailable")
  result["workflow_roles"] = %workflowRoles
  result["capabilities"] = %capabilities
  result["priority"] = %computePriority(subCfg, assignmentPolicy)

proc buildRuntimeAgentInventory*(cfg: JsonNode = loadRawConfig()): JsonNode =
  let groupsDoc = loadKernelArtifact("agents", "agent_groups")
  let assignmentPolicy = loadPolicySpec("assignment_policy")
  let detected = detectOverlaySubagents(cfg)
  let subagents = getSubagents(cfg)
  var agents: seq[JsonNode] = @[]
  if subagents.kind == JObject:
    for name, subCfg in subagents:
      if subCfg.kind != JObject:
        continue
      agents.add(buildAgentEntry(name, subCfg, detected{name}, groupsDoc, assignmentPolicy))

  result = %*{
    "artifact_name": "runtime_agent_inventory",
    "artifact_type": "runtime_agent_inventory",
    "source": "vida.config.yaml",
    "generated_at": nowUtc(),
    "agents": agents,
  }

## VIDA Assignment Engine — root config-driven lane/agent resolution.
##
## Reads product-law artifacts from `vida/config/{routes,agents,policies}`
## and resolves eligible agents for a given lane or task class.
## Concrete installed agent inventory is derived from `vida.config.yaml`.

import std/[algorithm, json, sequtils]
import ./[agent_inventory, kernel_config, utils]

proc kernelAssignmentReady*(): bool =
  let routeCatalog = loadRouteCatalog()
  let agentRegistry = buildRuntimeAgentInventory()
  routeCatalog.kind == JObject and routeCatalog.len > 0 and
    agentRegistry.kind == JObject and agentRegistry{"agents"}.kind == JArray

proc laneSpec(routeCatalog: JsonNode, lane: string): JsonNode =
  dottedGet(routeCatalog, "routes." & lane, newJObject())

proc taskClassBinding(routeCatalog: JsonNode, taskClass: string): JsonNode =
  dottedGet(routeCatalog, "task_class_bindings." & taskClass, newJObject())

proc taskClassLane*(taskClass: string, laneKind: string = "primary_lane"): string =
  let routeCatalog = loadRouteCatalog()
  let binding = taskClassBinding(routeCatalog, taskClass)
  let fallback = policyValue(dottedGet(routeCatalog, "defaults." & laneKind), "")
  policyValue(binding{laneKind}, fallback)

proc taskClassBindingBool*(taskClass, key: string, default: bool = false): bool =
  let routeCatalog = loadRouteCatalog()
  let binding = taskClassBinding(routeCatalog, taskClass)
  policyBool(binding{key}, default)

proc laneIndependenceClass*(lane: string): string =
  let routeCatalog = loadRouteCatalog()
  policyValue(laneSpec(routeCatalog, lane){"independence_class"}, "none")

proc workflowRoles(agent: JsonNode): seq[string] =
  let roles = splitCsv(agent{"workflow_roles"})
  if roles.len > 0:
    return roles
  return splitCsv(agent{"roles"})

proc capabilities(agent: JsonNode): seq[string] =
  splitCsv(agent{"capabilities"})

proc specialties(agent: JsonNode): seq[string] =
  splitCsv(agent{"specialties"})

proc candidateWriteScope(agent: JsonNode): string =
  policyValue(agent{"write_scope"}, "none")

proc candidateLoad(agentId: string, ctx: JsonNode): int =
  dottedGetInt(ctx, "current_load." & agentId, 0)

proc isSystemAgent(agent: JsonNode): bool =
  policyValue(agent{"agent_type"}, "") == "system_agent"

proc isHumanAgent(agent: JsonNode): bool =
  policyValue(agent{"agent_type"}, "") == "human_agent"

proc isActiveAgent(agent: JsonNode): bool =
  dottedGetBool(agent, "enabled", true) and
    policyValue(agent{"status"}, "active") == "active"

proc effectiveMode(ctx, assignmentPolicy: JsonNode): string =
  let ctxMode = policyValue(ctx{"effective_mode"}, "")
  if ctxMode.len > 0:
    return ctxMode
  return policyValue(dottedGet(assignmentPolicy, "runtime.mode"), "hybrid")

proc excludes(ctx: JsonNode): seq[string] =
  splitCsv(ctx{"exclude_agents"})

proc capabilityBonus(agent: JsonNode, taskClass, requiredCapability: string): int =
  var bonus = 0
  let caps = capabilities(agent)
  let specs = specialties(agent)
  if requiredCapability.len > 0 and requiredCapability in caps:
    bonus += 40
  if taskClass.len > 0 and taskClass in specs:
    bonus += 25
  if taskClass.len > 0 and taskClass in caps:
    bonus += 20
  if "web_search" in caps and dottedGetBool(%*{"required": dottedGetBool(agent, "web_search_required", false)}, "required", false):
    bonus += 5
  return bonus

proc preferredTraitBoost(agent, routeSpec: JsonNode): int =
  var bonus = 0
  let preferredAgentTypes = splitCsv(routeSpec{"preferred_agent_types"})
  if preferredAgentTypes.len > 0 and policyValue(agent{"agent_type"}, "") in preferredAgentTypes:
    bonus += 120

  let preferredWriteScopes = splitCsv(routeSpec{"preferred_write_scopes"})
  if preferredWriteScopes.len > 0 and candidateWriteScope(agent) in preferredWriteScopes:
    bonus += 90

  let preferredCapabilities = splitCsv(routeSpec{"preferred_capabilities"})
  if preferredCapabilities.len > 0:
    for capability in capabilities(agent):
      if capability in preferredCapabilities:
        bonus += 80
        break

  let preferredBillingTiers = splitCsv(routeSpec{"preferred_billing_tiers"})
  if preferredBillingTiers.len > 0 and policyValue(agent{"billing_tier"}, "") in preferredBillingTiers:
    bonus += 40

  let preferredCostPriorities = splitCsv(routeSpec{"preferred_cost_priorities"})
  if preferredCostPriorities.len > 0 and policyValue(agent{"cost_priority"}, "") in preferredCostPriorities:
    bonus += 30

  return bonus

proc candidatePayload(
  agent: JsonNode,
  lane, taskClass: string,
  score, load: int,
  selectionStrategy: string,
): JsonNode =
  %*{
    "subagent": policyValue(agent{"id"}, ""),
    "compatible": true,
    "lane": lane,
    "task_class": taskClass,
    "agent_type": policyValue(agent{"agent_type"}, ""),
    "workflow_roles": workflowRoles(agent),
    "capabilities": capabilities(agent),
    "write_scope": candidateWriteScope(agent),
    "billing_tier": policyValue(agent{"billing_tier"}, "unknown"),
    "speed_tier": policyValue(agent{"speed_tier"}, "unknown"),
    "quality_tier": policyValue(agent{"quality_tier"}, "unknown"),
    "priority": policyInt(agent{"priority"}, 0),
    "max_concurrency": policyInt(agent{"max_concurrency"}, 1),
    "budget_cost_units": policyInt(agent{"budget_cost_units"}, 0),
    "selection_strategy": selectionStrategy,
    "load": load,
    "effective_score": score,
  }

proc compareCandidates(a, b: JsonNode): int =
  let scoreA = policyInt(a{"effective_score"}, 0)
  let scoreB = policyInt(b{"effective_score"}, 0)
  if scoreA != scoreB:
    return cmp(scoreB, scoreA)
  let priorityA = policyInt(a{"priority"}, 0)
  let priorityB = policyInt(b{"priority"}, 0)
  if priorityA != priorityB:
    return cmp(priorityB, priorityA)
  let loadA = policyInt(a{"load"}, 0)
  let loadB = policyInt(b{"load"}, 0)
  if loadA != loadB:
    return cmp(loadA, loadB)
  return cmp(policyValue(a{"subagent"}, ""), policyValue(b{"subagent"}, ""))

proc selectCandidate(candidates: seq[JsonNode], selectionStrategy: string, ctx: JsonNode): string =
  if candidates.len == 0:
    return ""
  case selectionStrategy
  of "manual_assignment":
    return ""
  of "pinned_agent":
    let pinned = policyValue(ctx{"pinned_agent"}, "")
    if pinned.len > 0:
      for candidate in candidates:
        if policyValue(candidate{"subagent"}, "") == pinned:
          return pinned
    for candidate in candidates:
      if policyValue(candidate{"agent_type"}, "") == "system_agent":
        return policyValue(candidate{"subagent"}, "")
    return policyValue(candidates[0]{"subagent"}, "")
  else:
    return policyValue(candidates[0]{"subagent"}, "")

proc resolveAssignmentForLane*(lane: string, ctx: JsonNode = newJObject()): JsonNode =
  let routeCatalog = loadRouteCatalog()
  let assignmentPolicy = loadPolicySpec("assignment_policy")
  let registry = buildRuntimeAgentInventory()
  let spec = laneSpec(routeCatalog, lane)
  if spec.kind != JObject or spec.len == 0:
    return %*{"ok": false, "lane": lane, "reason": "unknown_lane", "candidates": []}
  let agents = registry{"agents"}
  if agents.kind != JArray:
    return %*{"ok": false, "lane": lane, "reason": "missing_agent_registry", "candidates": []}

  let requiredRoles = splitCsv(spec{"required_roles"})
  let requiredCapability = policyValue(spec{"capability"}, "")
  let assignmentMode = policyValue(spec{"assignment_mode"}, "single")
  let independenceClass = policyValue(spec{"independence_class"}, "none")
  let selectionStrategy =
    policyValue(
      spec{"selection_strategy"},
      policyValue(dottedGet(assignmentPolicy, "defaults." & lane), "priority"),
    )
  let mode = effectiveMode(ctx, assignmentPolicy)
  let excludedAgents = excludes(ctx)
  let taskClass = policyValue(ctx{"task_class"}, "")
  let externalFirstRequired = policyBool(ctx{"external_first_required"}, false)
  let routeExternalFirst = dottedGetBool(spec, "external_first_required", false)
  let requireExternalFirst = externalFirstRequired or routeExternalFirst
  let maxBudgetUnits = dottedGetInt(ctx, "max_budget_units", -1)

  if mode == "disabled":
    return %*{
      "ok": false,
      "lane": lane,
      "reason": "assignment_runtime_disabled",
      "selection_strategy": selectionStrategy,
      "candidates": [],
    }

  var candidates: seq[JsonNode] = @[]
  var externalCandidateExists = false
  for agent in agents:
    if agent.kind != JObject:
      continue
    let agentId = policyValue(agent{"id"}, "")
    if agentId.len == 0 or not isActiveAgent(agent):
      continue
    if mode == "native" and not isSystemAgent(agent):
      continue
    if selectionStrategy == "human_required" and not isHumanAgent(agent):
      continue
    if independenceClass in ["human_independent_required", "service_independent_required"] and not isHumanAgent(agent):
      continue
    if independenceClass != "none" and agentId in excludedAgents:
      continue
    let roles = workflowRoles(agent)
    if requiredRoles.len > 0 and (roles.filterIt(it in requiredRoles)).len == 0:
      continue
    let caps = capabilities(agent)
    if requiredCapability.len > 0 and requiredCapability notin caps:
      continue
    if maxBudgetUnits >= 0 and policyInt(agent{"budget_cost_units"}, 0) > maxBudgetUnits:
      continue

    let load = candidateLoad(agentId, ctx)
    var score = policyInt(agent{"priority"}, 0)
    let fit = capabilityBonus(agent, taskClass, requiredCapability)
    score += preferredTraitBoost(agent, spec)
    case selectionStrategy
    of "least_loaded":
      score = score + fit - (load * 100)
    of "capability_score":
      score = score + (fit * 4) - (load * 10)
    of "strict_independent":
      score = score + (fit * 2) - (load * 20)
    of "first_eligible":
      score = score + fit
    of "human_required":
      score = score + fit
    of "pinned_agent":
      if agentId == policyValue(ctx{"pinned_agent"}, ""):
        score += 1000
    else:
      score = score + fit - (load * 10)

    let candidate = candidatePayload(agent, lane, taskClass, score, load, selectionStrategy)
    if not isSystemAgent(agent):
      externalCandidateExists = true
    candidates.add(candidate)

  if requireExternalFirst and externalCandidateExists:
    for candidate in mitems(candidates):
      if policyValue(candidate{"agent_type"}, "") == "system_agent":
        candidate["effective_score"] = %(policyInt(candidate{"effective_score"}, 0) - 1000)

  candidates.sort(compareCandidates)
  let selected = selectCandidate(candidates, selectionStrategy, ctx)
  let ok = selected.len > 0 and assignmentMode != "manual"
  let reason =
    if assignmentMode == "manual":
      "manual_assignment_required"
    elif selected.len > 0:
      "selected"
    else:
      "no_eligible_agent"

  result = %*{
    "ok": ok,
    "source": "root_config",
    "inventory_source": "overlay_runtime",
    "lane": lane,
    "route_stage": policyValue(spec{"route_stage"}, ""),
    "required_roles": requiredRoles,
    "capability": requiredCapability,
    "assignment_mode": assignmentMode,
    "selection_strategy": selectionStrategy,
    "independence_class": independenceClass,
    "selected_subagent": (if selected.len > 0: %selected else: newJNull()),
    "reason": reason,
    "candidates": candidates,
  }

proc resolveAssignmentForTaskClass*(taskClass: string, ctx: JsonNode = newJObject()): JsonNode =
  let lane = taskClassLane(taskClass)
  if lane.len == 0:
    return %*{
      "ok": false,
      "task_class": taskClass,
      "reason": "unbound_task_class",
      "candidates": [],
    }
  var laneCtx = normalizeJson(ctx)
  if laneCtx.kind != JObject:
    laneCtx = newJObject()
  laneCtx["task_class"] = %taskClass
  let payload = resolveAssignmentForLane(lane, laneCtx)
  result = normalizeJson(payload)
  result["task_class"] = %taskClass

## VIDA Kernel Runtime CLI — root config introspection, assignment, and transition evaluation.

import std/json
import ./[agent_inventory, assignment_engine, kernel_config, transition_engine, toon, utils]

proc printHelp() =
  echo """
Usage:
  vida-legacy kernel summary
  vida-legacy kernel machine <name> [--json]
  vida-legacy kernel route <name> [--json]
  vida-legacy kernel agents [--json]
  vida-legacy kernel policy <name> [--json]
  vida-legacy kernel assign lane <lane> [context_json] [--json]
  vida-legacy kernel assign task-class <task_class> [context_json] [--json]
  vida-legacy kernel transition <machine> <current_state> <command> [context_json]
"""

proc emitPayload(payload: JsonNode, asJson: bool) =
  if asJson:
    echo pretty(normalizeJson(payload))
  else:
    echo renderToon(normalizeJson(payload))

proc wantsJson(args: seq[string]): bool =
  for arg in args:
    if arg == "--json":
      return true
  false

proc cmdKernel*(args: seq[string]): int =
  if args.len == 0:
    printHelp()
    return 1

  case args[0]
  of "summary":
    emitPayload(kernelSummary(), wantsJson(args))
    return 0

  of "machine":
    if args.len < 2:
      echo "Usage: vida-legacy kernel machine <name> [--json]"
      return 1
    let payload = loadMachineSpec(args[1])
    if payload.kind != JObject or payload.len == 0:
      echo "unknown machine: " & args[1]
      return 1
    emitPayload(payload, wantsJson(args))
    return 0

  of "route":
    if args.len < 2:
      echo "Usage: vida-legacy kernel route <name> [--json]"
      return 1
    let catalog = loadRouteCatalog()
    let payload = dottedGet(catalog, "routes." & args[1], newJObject())
    if payload.kind != JObject or payload.len == 0:
      echo "unknown route: " & args[1]
      return 1
    emitPayload(%*{"route_name": args[1], "route": payload}, wantsJson(args))
    return 0

  of "agents":
    emitPayload(buildRuntimeAgentInventory(), wantsJson(args))
    return 0

  of "policy":
    if args.len < 2:
      echo "Usage: vida-legacy kernel policy <name> [--json]"
      return 1
    let payload = loadPolicySpec(args[1])
    if payload.kind != JObject or payload.len == 0:
      echo "unknown policy: " & args[1]
      return 1
    emitPayload(payload, wantsJson(args))
    return 0

  of "assign":
    if args.len < 3:
      echo "Usage: vida-legacy kernel assign <lane|task-class> <name> [context_json] [--json]"
      return 1
    let ctx =
      if args.len >= 4 and args[3] != "--json":
        try:
          parseJson(args[3])
        except:
          echo "invalid context_json"
          return 1
      else:
        newJObject()
    let payload =
      case args[1]
      of "lane":
        resolveAssignmentForLane(args[2], ctx)
      of "task-class":
        resolveAssignmentForTaskClass(args[2], ctx)
      else:
        echo "Usage: vida-legacy kernel assign <lane|task-class> <name> [context_json] [--json]"
        return 1
    emitPayload(payload, wantsJson(args))
    return (if dottedGetBool(payload, "ok", false): 0 else: 1)

  of "transition":
    if args.len < 4:
      echo "Usage: vida-legacy kernel transition <machine> <current_state> <command> [context_json]"
      return 1
    let machine = loadMachineSpec(args[1])
    if machine.kind != JObject or machine.len == 0:
      echo "unknown machine: " & args[1]
      return 1
    let ctx =
      if args.len >= 5:
        try:
          parseJson(args[4])
        except:
          echo "invalid context_json"
          return 1
      else:
        newJObject()
    let payload = applyTransition(machine, args[2], args[3], ctx)
    emitPayload(payload, wantsJson(args))
    return (if dottedGetBool(payload, "ok", false): 0 else: 1)

  else:
    echo "Unknown kernel subcommand: " & args[0]
    return 1

## VIDA Route Resolution — route snapshot, receipt writing, mutation tracking.
##
## Extracted from `subagent-dispatch.py` (5835 lines → ~350 lines route core).
## Builds route snapshots, writes receipts, tracks framework/project mutations,
## and provides route receipt hashing.

import std/[json, os, strutils, sequtils, hashes, times]
import ../core/[assignment_engine, utils, config, toon]
import ./[system, registry]

# ─────────────────────────── Paths ───────────────────────────

proc routeReceiptDir*(): string = vidaRoot() / ".vida" / "logs" / "route-receipts"
proc issueContractDir*(): string = vidaRoot() / ".vida" / "logs" / "issue-contracts"
proc specIntakeDir*(): string = vidaRoot() / ".vida" / "logs" / "spec-intake"
proc specDeltaDir*(): string = vidaRoot() / ".vida" / "logs" / "spec-deltas"
proc draftExecSpecDir*(): string = vidaRoot() / ".vida" / "logs" / "draft-execution-specs"
proc runLogPath*(): string = vidaRoot() / ".vida" / "logs" / "subagent-runs.jsonl"

proc routeReceiptPath*(taskId, taskClass: string): string =
  routeReceiptDir() / (safeName(taskId, "task") & "." & safeName(taskClass, "tc") & ".route.json")

proc analysisReceiptPath*(taskId, taskClass: string): string =
